def detect_anomalies(
    file_name: str,
    bronze_dir: str = "data/1_bronze"
) -> Dict[str, Any]:
    """Scans for negatives and ALL date columns."""
    bronze_path = Path(bronze_dir) / file_name

    if not bronze_path.exists():
        return {"negatives": {}, "date_columns": {}}

    df = (
        pd.read_csv(bronze_path, keep_default_na=False, dtype=str)
        .replace("", np.nan)
    )

    anomalies = {"negatives": {}, "date_columns": {}}

    # 1. Detect negative values
    for col in df.columns:
        numeric_col = pd.to_numeric(df[col], errors="coerce")

        if not numeric_col.isnull().all():
            neg_count = (numeric_col < 0).sum()

            if neg_count > 0:
                anomalies["negatives"][col] = int(neg_count)

    # 2. Detect ALL Date Columns
    def get_date_format(date_str):
        if pd.isna(date_str):
            return None

        date_str = str(date_str).strip()

        if re.match(r"^\d{4}-\d{1,2}-\d{1,2}", date_str):
            return "YYYY-MM-DD"

        if re.match(r"^\d{1,2}[/-]\d{1,2}[/-]\d{4}", date_str):
            return "MM/DD/YYYY"

        if re.match(r"^\d{1,2}-[A-Za-z]{3}-\d{4}", date_str):
            return "DD-Mon-YYYY"

        if pd.to_datetime(date_str, errors="coerce") is not pd.NaT:
            return "Other/Mixed"

        return None

    for col in df.columns:
        series = df[col].dropna()

        if series.empty:
            continue

        is_date_col = "date" in col.lower()

        if not is_date_col and series.dtype == "object":
            sample = series.head(50)
            parsed = pd.to_datetime(sample, errors="coerce")

            if parsed.notna().sum() > (len(sample) * 0.5):
                if not pd.to_numeric(sample, errors="coerce").notna().all():
                    is_date_col = True

        if is_date_col:
            sample_for_formats = series.sample(
                n=min(100, len(series)),
                random_state=1
            )

            detected = {
                fmt
                for fmt in sample_for_formats.apply(get_date_format)
                if fmt is not None
            }

            if not detected:
                detected = {"Unknown/Mixed"}

            anomalies["date_columns"][col] = sorted(list(detected))

    return anomalies


def clean_bronze_csv(
    file_name: str,
    cols_to_fix_negatives: List[str] = None,
    target_date_formats: Dict[str, str] = None,
    bronze_dir: str = "data/1_bronze",
    silver_dir: str = "data/2_silver"
) -> Dict[str, Any]:
    if cols_to_fix_negatives is None:
        cols_to_fix_negatives = []

    if target_date_formats is None:
        target_date_formats = {}

    df = pd.read_csv(Path(bronze_dir) / file_name, keep_default_na=True)

    before_df = df.copy(deep=True)
    after_df = df.copy()
    audit_log = []

    original_columns = list(after_df.columns)

    cleaned_columns = [
        str(col).strip().lower().replace(" ", "_")
        for col in original_columns
    ]

    after_df.columns = cleaned_columns
    col_map = dict(zip(original_columns, cleaned_columns))

    if original_columns != cleaned_columns:
        audit_log.append(
            f"Standardized {len(cleaned_columns)} column name(s)."
        )

    date_code_map = {
        "YYYY-MM-DD": "%Y-%m-%d",
        "MM/DD/YYYY": "%m/%d/%Y",
        "DD-MM-YYYY": "%d-%m-%Y",
        "DD-Mon-YYYY": "%d-%b-%Y",
    }

    for orig_col, target_format in target_date_formats.items():
        clean_col = col_map.get(orig_col, orig_col)

        if clean_col in after_df.columns:

            def safe_parse(value):
                if pd.isna(value) or str(value).strip() == "":
                    return pd.NaT

                return pd.to_datetime(str(value).strip(), errors="coerce")

            parsed_series = pd.to_datetime(
                after_df[clean_col].apply(safe_parse)
            )

            format_code = date_code_map.get(
                target_format,
                "%Y-%m-%d"
            )

            after_df[clean_col] = parsed_series.dt.strftime(format_code)

            audit_log.append(
                f"Standardized dates in '{clean_col}' "
                f"to format: {target_format}."
            )

    if cols_to_fix_negatives:
        mapped_fix_negatives = [
            col_map.get(col, col)
            for col in cols_to_fix_negatives
        ]

        for col in mapped_fix_negatives:
            if (
                col in after_df.columns
                and pd.api.types.is_numeric_dtype(after_df[col])
            ):
                neg_mask = after_df[col] < 0

                if neg_mask.any():
                    after_df[col] = after_df[col].abs()

                    audit_log.append(
                        f"Converted {neg_mask.sum()} negative value(s) "
                        f"to positive in '{col}'."
                    )

    for col in after_df.columns:
        if after_df[col].dtype == "object":
            after_df[col] = after_df[col].apply(
                lambda value: value.strip()
                if isinstance(value, str)
                else value
            )

        if after_df[col].isnull().any():
            null_count = after_df[col].isnull().sum()

            fill_val = (
                0
                if pd.api.types.is_numeric_dtype(after_df[col])
                else "Unknown"
            )

            after_df[col] = after_df[col].fillna(fill_val)

            audit_log.append(
                f"Filled {null_count} missing value(s) in '{col}' "
                f"with '{fill_val}'."
            )

    if not audit_log:
        audit_log.append(
            "Data was already clean; no modifications were necessary."
        )

    silver_path = Path(silver_dir)
    silver_path.mkdir(parents=True, exist_ok=True)

    after_df.to_csv(silver_path / file_name, index=False)

    comparison_rows = []

    for i in range(len(before_df)):
        b_row = before_df.iloc[i]
        a_row = after_df.iloc[i]

        for orig_col, clean_col in col_map.items():
            b_val = b_row.get(orig_col)
            a_val = a_row.get(clean_col)

            b_str = str(b_val)
            a_str = str(a_val)

            if pd.isna(b_val):
                b_str = "Null"

            if pd.isna(a_val):
                a_str = "Null"

            if b_str != a_str:
                comparison_rows.append(
                    {
                        "Row #": i + 1,
                        "Column": orig_col,
                        "Before": b_str,
                        "After": a_str,
                    }
                )

        if len(comparison_rows) >= 15:
            break

    return {
        "audit_log": audit_log,
        "comparison_dataframe": pd.DataFrame(comparison_rows),
    }


def evaluate_silver_join_keys(
    file_names: List[str],
    silver_dir: str = "data/2_silver"
):
    profiles = []
    potential_keys = []

    for file_name in file_names:
        path = Path(silver_dir) / file_name

        if path.exists():
            profiles.append(
                {
                    "file": file_name,
                    "columns": set(
                        pd.read_csv(path, nrows=0).columns
                    ),
                }
            )

    if len(profiles) > 1:
        for profile_1, profile_2 in itertools.combinations(
            profiles,
            2
        ):
            common = sorted(
                list(
                    profile_1["columns"].intersection(
                        profile_2["columns"]
                    )
                )
            )

            if common:
                potential_keys.append(
                    {
                        "file_1": profile_1["file"],
                        "file_2": profile_2["file"],
                        "common_columns": common,
                    }
                )

    return potential_keys


