def create_gold_join(
    file_1: str,
    file_2: str,
    join_keys: List[str],
    silver_dir: str = "data/2_silver",
    gold_dir: str = "data/3_gold"
) -> str:
    """Merges two cleaned Silver tables and saves the enriched dataset to Gold."""
    df1 = pd.read_csv(Path(silver_dir) / file_1)
    df2 = pd.read_csv(Path(silver_dir) / file_2)

    joined_df = pd.merge(
        df1,
        df2,
        on=join_keys,
        how="left",
        suffixes=("_base", "_enriched"),
    )

    joined_name = (
        f"joined_{Path(file_1).stem}_{Path(file_2).stem}.csv"
    )

    gold_path = Path(gold_dir)
    gold_path.mkdir(parents=True, exist_ok=True)

    joined_df.to_csv(gold_path / joined_name, index=False)

    return joined_name


def generate_gold_insights(
    file_name: str,
    is_joined: bool = False,
    silver_dir: str = "data/2_silver",
    gold_dir: str = "data/3_gold"
) -> Dict[str, Any]:
    """Generates business summaries, takeaways, and Plotly charts."""
    read_path = (
        Path(gold_dir) / file_name
        if is_joined
        else Path(silver_dir) / file_name
    )

    if not read_path.exists():
        raise FileNotFoundError(f"Source file not found: {read_path}")

    df = pd.read_csv(read_path)

    numeric_cols = list(
        df.select_dtypes(include=[np.number]).columns
    )

    object_cols = list(
        df.select_dtypes(include=["object"]).columns
    )

    date_cols = [
        col
        for col in df.columns
        if "date" in col.lower() or "time" in col.lower()
    ]

    for date_col in date_cols:
        if date_col in object_cols:
            object_cols.remove(date_col)

    measurable_numerics = [
        col
        for col in numeric_cols
        if not any(
            word in col.lower()
            for word in ["id", "zip", "code"]
        )
    ]

    primary_numeric = (
        measurable_numerics[0]
        if measurable_numerics
        else numeric_cols[0]
        if numeric_cols
        else None
    )

    grouping_col = None

    if object_cols:
        priority_cats = [
            col
            for col in object_cols
            if any(
                word in col.lower()
                for word in [
                    "region",
                    "city",
                    "state",
                    "category",
                    "segment",
                    "store_name",
                ]
            )
        ]

        valid_cats = [
            col
            for col in object_cols
            if 1 < df[col].nunique() < 100
        ]

        if priority_cats:
            grouping_col = priority_cats[0]
        elif valid_cats:
            grouping_col = valid_cats[0]
        else:
            grouping_col = object_cols[0]

    summary_df = pd.DataFrame()
    insights = []

    bar_chart = None
    line_chart = None
    treemap_chart = None

    # Aggregations and Bar Chart
    if primary_numeric and grouping_col:
        summary_df = (
            df.groupby(grouping_col)[primary_numeric]
            .agg(
                sum="sum",
                average="mean",
                count="count",
            )
            .reset_index()
        )

        summary_df = (
            summary_df
            .sort_values("sum", ascending=False)
            .reset_index(drop=True)
        )

        top_cat = summary_df.iloc[0]

        insights.append(
            f"🏆 **Top Performer:** `{top_cat[grouping_col]}` "
            f"leads with a total "
            f"{primary_numeric.replace('_', ' ')} of "
            f"**{top_cat['sum']:,.2f}**."
        )

        insights.append(
            f"📊 **Averages:** The overall average "
            f"{primary_numeric.replace('_', ' ')} per record is "
            f"**{df[primary_numeric].mean():,.2f}**."
        )

        bar_chart = px.bar(
            summary_df.head(10),
            x=grouping_col,
            y="sum",
            title=(
                f"Top 10 "
                f"{grouping_col.replace('_', ' ').title()} by Total "
                f"{primary_numeric.replace('_', ' ').title()}"
            ),
            template="plotly_white",
        )

    elif grouping_col:
        summary_df = (
            df[grouping_col]
            .value_counts()
            .reset_index(name="row_count")
        )

        summary_df.columns = [grouping_col, "row_count"]

        top_cat = summary_df.iloc[0]

        insights.append(
            f"🏆 **Highest Frequency:** `{top_cat[grouping_col]}` "
            f"is the most common, appearing "
            f"**{top_cat['row_count']:,}** times."
        )

        insights.append(
            f"📊 **Distribution:** The dataset contains "
            f"{df[grouping_col].nunique()} unique categories in "
            f"`{grouping_col}`."
        )

        bar_chart = px.bar(
            summary_df.head(10),
            x=grouping_col,
            y="row_count",
            title=(
                f"Top 10 "
                f"{grouping_col.replace('_', ' ').title()} by Volume"
            ),
            template="plotly_white",
        )

    # Line Chart: Trend over time
    if date_cols and primary_numeric:
        date_col = date_cols[0]

        trend_df = (
            df.groupby(date_col)[primary_numeric]
            .sum()
            .reset_index()
            .sort_values(date_col)
        )

        line_chart = px.line(
            trend_df,
            x=date_col,
            y=primary_numeric,
            markers=True,
            title=(
                f"Trend of "
                f"{primary_numeric.replace('_', ' ').title()} over Time"
            ),
            template="plotly_white",
        )

    elif date_cols:
        date_col = date_cols[0]

        trend_df = (
            df[date_col]
            .value_counts()
            .reset_index(name="row_count")
            .sort_values(date_col)
        )

        line_chart = px.line(
            trend_df,
            x=date_col,
            y="row_count",
            markers=True,
            title="Data Volume over Time",
            template="plotly_white",
        )

    # Treemap: Geographic or Hierarchical
    location_columns = [
        col
        for col in [
            "region",
            "state",
            "city",
            "category",
            "subcategory",
        ]
        if col in df.columns
    ]

    if len(location_columns) >= 2:
        loc_df = (
            df.groupby(location_columns)
            .size()
            .reset_index(name="count")
        )

        treemap_chart = px.treemap(
            loc_df,
            path=[px.Constant("All")] + location_columns,
            values="count",
            title=(
                "Hierarchical Distribution "
                "(e.g. Region -> State -> City)"
            ),
        )

    # Save summary to Gold layer
    gold_path = Path(gold_dir)
    gold_path.mkdir(parents=True, exist_ok=True)

    if not summary_df.empty:
        summary_df.to_csv(
            gold_path / f"gold_summary_{file_name}",
            index=False,
        )

    return {
        "summary_df": summary_df,
        "insights": insights,
        "bar_chart": bar_chart,
        "line_chart": line_chart,
        "treemap_chart": treemap_chart,
    }


